class Solution:
    def pushDominoes(self, dominoes):
        # simulate second by second until stable
        cur = list(dominoes)
        while True:
            nxt = cur[:]
            n = len(cur)
            for i in range(n):
                if cur[i] == '.':
                    left_push = (i > 0 and cur[i - 1] == 'R')
                    right_push = (i < n - 1 and cur[i + 1] == 'L')
                    if left_push and not right_push:
                        nxt[i] = 'R'
                    elif right_push and not left_push:
                        nxt[i] = 'L'
            if nxt == cur:
                return ''.join(cur)
            cur = nxt

