class Solution:
    def pushDominoes(self, dominoes):
        n = len(dominoes)
        force = [0] * n
        f = 0
        for i in range(n):
            if dominoes[i] == 'R':
                f = n
            elif dominoes[i] == 'L':
                f = 0
            else:
                f = max(f - 1, 0)
            force[i] += f
        f = 0
        for i in range(n - 1, -1, -1):
            if dominoes[i] == 'L':
                f = n
            elif dominoes[i] == 'R':
                f = 0
            else:
                f = max(f - 1, 0)
            force[i] -= f
        res = []
        for x in force:
            if x > 0:
                res.append('R')
            elif x < 0:
                res.append('L')
            else:
                res.append('.')
        return ''.join(res)

