var pushDominoes = function(dominoes) {
    const n = dominoes.length;
    const force = new Array(n).fill(0);
    let f = 0;
    for (let i = 0; i < n; i++) {
        if (dominoes[i] === 'R') f = n;
        else if (dominoes[i] === 'L') f = 0;
        else f = Math.max(f - 1, 0);
        force[i] += f;
    }
    f = 0;
    for (let i = n - 1; i >= 0; i--) {
        if (dominoes[i] === 'L') f = n;
        else if (dominoes[i] === 'R') f = 0;
        else f = Math.max(f - 1, 0);
        force[i] -= f;
    }
    let res = '';
    for (const x of force) {
        if (x > 0) res += 'R';
        else if (x < 0) res += 'L';
        else res += '.';
    }
    return res;
};
